-- Menja Fresh — Spinach Croquettes (Spinat-Kroketten)
-- Vegetarian, protein-rich. For 4 people. Run in Supabase SQL Editor. Idempotent.

INSERT INTO public.recipes (id,title,subtitle,emoji,image_url,tags,meal,categories,diet,is_kids,prep_minutes,cook_minutes,servings,nutrition,ingredients,dressing,base_ingredients,steps,i18n) VALUES (
 'spinach-croquettes', 'Spinach Croquettes', 'Crisp pan-fried croquettes of spinach, parmesan & pine nuts — vegetarian & protein-rich', '🥬', NULL,
 ARRAY['Vegetarian','High-protein'], ARRAY['Main Course'], ARRAY['Vegetables'], ARRAY['vegetarian'],
 false, 20, 15, 4,
 '{"kcal":380,"protein":21,"carbs":18,"fat":24,"fiber":4}'::jsonb, '[{"emoji":"🥬","name":"Spinach (fresh, or frozen)","amount":"1kg"},{"emoji":"🧅","name":"Red onion","amount":"1 medium"},{"emoji":"🧄","name":"Garlic","amount":"1 large clove"},{"emoji":"🧀","name":"Parmesan, grated","amount":"100g"},{"emoji":"🥚","name":"Egg","amount":"1 medium"},{"emoji":"🌰","name":"Pine nuts","amount":"30g"},{"emoji":"🍞","name":"Coarse dry breadcrumbs","amount":"2 handfuls (~80g)"}]'::jsonb, NULL, '["Salt","Black pepper","Nutmeg","Olive oil for frying"]'::jsonb, '[{"title":"Wilt & dry the spinach","text":"Wilt the fresh spinach in a hot pan (or a quick blanch), then let it cool. Squeeze it really dry with your hands and chop finely. Using frozen spinach? Thaw it and squeeze out all the water the same way.","ings":["🥬 Spinach · 1kg"],"tip":"The drier the spinach, the crisper the croquettes — wet spinach makes them fall apart."},{"title":"Toast the pine nuts & soften the aromatics","text":"Toast the pine nuts in a dry pan until golden, then set aside. Finely dice the onion and garlic and sauté in a little olive oil until soft and sweet.","ings":["🌰 Pine nuts · 30g","🧅 Red onion · 1","🧄 Garlic · 1 clove"]},{"title":"Mix the croquette dough","text":"In a bowl combine the chopped spinach, onion, garlic, grated parmesan, egg, pine nuts and coarse breadcrumbs. Season well with salt, pepper and freshly grated nutmeg. The mix should just hold together — add a little more breadcrumb if it feels wet.","ings":["🧀 Parmesan · 100g","🥚 Egg · 1","🍞 Breadcrumbs · 2 handfuls"]},{"title":"Shape the croquettes","text":"With damp hands, form the mixture into small croquettes or logs — you should get about 12.","ings":[]},{"title":"Fry until golden","text":"Heat a little olive oil in a pan over medium heat and fry the croquettes, turning, until crisp and golden on all sides, about 3–4 minutes per side. Drain on kitchen paper and serve warm. (You can also bake them at 200°C for 20–25 minutes.)","ings":[]}]'::jsonb, '{"de":{"title":"Spinat-Kroketten","subtitle":"Knusprige Kroketten aus Spinat, Parmesan & Pinienkernen — vegetarisch & proteinreich","ingredients":["Spinat (frisch, oder tiefgekühlt)","Rote Zwiebel","Knoblauch","Parmesan, gerieben","Ei","Pinienkerne","Grob geriebenes hartes Brot"],"base":["Salz","Schwarzer Pfeffer","Muskatnuss","Olivenöl zum Braten"],"steps":[{"title":"Spinat garen & trocknen","text":"Den frischen Spinat in einer heißen Pfanne zusammenfallen lassen (oder kurz blanchieren) und abkühlen lassen. Mit den Händen richtig gut ausdrücken und fein hacken. Bei TK-Spinat: auftauen und ebenso das Wasser gründlich ausdrücken.","ings":["🥬 Spinat · 1kg"],"tip":"Je trockener der Spinat, desto knuspriger die Kroketten — nasser Spinat lässt sie zerfallen."},{"title":"Pinienkerne rösten & Zwiebel anschwitzen","text":"Die Pinienkerne in einer trockenen Pfanne goldbraun rösten und beiseitestellen. Zwiebel und Knoblauch fein würfeln und in etwas Olivenöl weich und süßlich anschwitzen.","ings":["🌰 Pinienkerne · 30g","🧅 Rote Zwiebel · 1","🧄 Knoblauch · 1 Zehe"]},{"title":"Kroketten-Masse mischen","text":"Gehackten Spinat, Zwiebel, Knoblauch, geriebenen Parmesan, Ei, Pinienkerne und das grob geriebene Brot in einer Schüssel verkneten. Kräftig mit Salz, Pfeffer und frisch geriebener Muskatnuss würzen. Die Masse soll gerade zusammenhalten — bei Bedarf noch etwas Brot zugeben.","ings":["🧀 Parmesan · 100g","🥚 Ei · 1","🍞 Hartes Brot · 2 Hände voll"]},{"title":"Kroketten formen","text":"Mit angefeuchteten Händen zu kleinen Kroketten bzw. länglichen Rollen formen — es werden etwa 12 Stück.","ings":[]},{"title":"Goldbraun braten","text":"Etwas Olivenöl in einer Pfanne bei mittlerer Hitze erhitzen und die Kroketten rundum knusprig goldbraun braten, ca. 3–4 Minuten pro Seite. Auf Küchenpapier abtropfen lassen und warm servieren. (Alternativ bei 200 °C 20–25 Minuten backen.)","ings":[]}]},"fr":{"title":"Croquettes d’épinards","subtitle":"Croquettes croustillantes d’épinards, parmesan & pignons — végétariennes et riches en protéines","ingredients":["Épinards (frais, ou surgelés)","Oignon rouge","Ail","Parmesan, râpé","Œuf","Pignons de pin","Chapelure grossière de pain sec"],"base":["Sel","Poivre noir","Muscade","Huile d’olive pour la cuisson"],"steps":[{"title":"Faire tomber & sécher les épinards","text":"Fais tomber les épinards frais dans une poêle chaude (ou blanchis-les rapidement), puis laisse refroidir. Presse-les vraiment bien à la main et hache-les finement. Épinards surgelés ? Décongèle-les et presse-en toute l’eau de la même façon.","ings":["🥬 Épinards · 1kg"],"tip":"Plus les épinards sont secs, plus les croquettes sont croustillantes — des épinards humides les font s’effriter."},{"title":"Torréfier les pignons & attendrir l’oignon","text":"Torréfie les pignons dans une poêle sèche jusqu’à ce qu’ils dorent, puis réserve. Émince finement l’oignon et l’ail et fais-les revenir dans un peu d’huile d’olive jusqu’à ce qu’ils soient fondants.","ings":["🌰 Pignons de pin · 30g","🧅 Oignon rouge · 1","🧄 Ail · 1 gousse"]},{"title":"Mélanger la pâte à croquettes","text":"Dans un bol, mélange les épinards hachés, l’oignon, l’ail, le parmesan râpé, l’œuf, les pignons et la chapelure grossière. Assaisonne généreusement de sel, poivre et muscade fraîchement râpée. Le mélange doit tout juste se tenir — ajoute un peu de chapelure s’il est trop humide.","ings":["🧀 Parmesan · 100g","🥚 Œuf · 1","🍞 Pain sec · 2 poignées"]},{"title":"Former les croquettes","text":"Les mains humides, façonne le mélange en petites croquettes ou boudins — tu devrais en obtenir une douzaine.","ings":[]},{"title":"Frire jusqu’à dorure","text":"Chauffe un peu d’huile d’olive dans une poêle à feu moyen et fais frire les croquettes en les retournant, jusqu’à ce qu’elles soient croustillantes et dorées sur toutes les faces, 3–4 minutes par côté. Égoutte sur du papier absorbant et sers chaud. (Tu peux aussi les cuire au four à 200 °C pendant 20–25 minutes.)","ings":[]}]},"es":{"title":"Croquetas de espinacas","subtitle":"Croquetas crujientes de espinacas, parmesano y piñones — vegetarianas y ricas en proteína","ingredients":["Espinacas (frescas, o congeladas)","Cebolla roja","Ajo","Parmesano, rallado","Huevo","Piñones","Pan seco rallado grueso"],"base":["Sal","Pimienta negra","Nuez moscada","Aceite de oliva para freír"],"steps":[{"title":"Pochar y secar las espinacas","text":"Pocha las espinacas frescas en una sartén caliente (o escáldalas un momento) y deja que se enfríen. Escúrrelas muy bien con las manos y pícalas finas. ¿Espinacas congeladas? Descongélalas y exprime toda el agua igual.","ings":["🥬 Espinacas · 1kg"],"tip":"Cuanto más secas las espinacas, más crujientes las croquetas — las espinacas húmedas las deshacen."},{"title":"Tostar los piñones y pochar la cebolla","text":"Tuesta los piñones en una sartén seca hasta que doren y resérvalos. Pica fina la cebolla y el ajo y sofríelos en un poco de aceite de oliva hasta que estén tiernos.","ings":["🌰 Piñones · 30g","🧅 Cebolla roja · 1","🧄 Ajo · 1 diente"]},{"title":"Mezclar la masa de croquetas","text":"En un bol mezcla las espinacas picadas, la cebolla, el ajo, el parmesano rallado, el huevo, los piñones y el pan rallado grueso. Sazona bien con sal, pimienta y nuez moscada recién rallada. La masa debe apenas ligar — añade un poco más de pan si queda húmeda.","ings":["🧀 Parmesano · 100g","🥚 Huevo · 1","🍞 Pan seco · 2 puñados"]},{"title":"Formar las croquetas","text":"Con las manos húmedas, forma la mezcla en croquetas pequeñas o cilindros — saldrán unas 12.","ings":[]},{"title":"Freír hasta dorar","text":"Calienta un poco de aceite de oliva en una sartén a fuego medio y fríe las croquetas, girándolas, hasta que estén crujientes y doradas por todos lados, unos 3–4 minutos por cara. Escúrrelas sobre papel de cocina y sirve calientes. (También puedes hornearlas a 200 °C durante 20–25 minutos.)","ings":[]}]}}'::jsonb
)
